import React, { Component } from 'react';
import { Router, Route, Switch } from 'react-router-dom';
import { createBrowserHistory } from 'history';
import { Provider } from 'react-redux';
import store from './redux/store';
import jwt_decode from 'jwt-decode';
import { setCurrentUser, logoutUser } from './redux/actions/authentication';
import setAuthToken from './redux/functions/setAuthToken';

import ScrollToTop from './functions/ScrollToTop';

import MainApp from './components/App/MainApp';
// Layouts of app
import { IntroductionLayout, AuthLayout } from './components/Layouts';
// Introduction pages
import { Landing } from './components/Pages/Introduction';
// Auth pages
import { Signup, Login, PasswordResetRequest, PasswordResetChange } from './components/Pages/Auth';

const AppRoute = ({ component: Component, layout: Layout, ...rest }) => (
    <Route {...rest} render={props => (
      <Layout>
        <Component {...props} />
      </Layout>
    )} />
)



if (localStorage.jwtToken) {
  setAuthToken(localStorage.jwtToken);
  const decoded = jwt_decode(localStorage.jwtToken);
  store.dispatch(setCurrentUser(decoded, {}));

  const currentTime = Date.now() / 1000;
  if (decoded.exp < currentTime) {
      store.dispatch(logoutUser());
      window.location.href = '/login';
  }
}



class App extends Component {

  constructor() {
      super();
      this.state = {
          socket: null
      };
  }

  render() {

    return(
      <Provider store={store}>
        <Router history={createBrowserHistory()}>
          <Switch>
            <ScrollToTop>
              {/* <AppRoute exact path="/" layout={IntroductionLayout} component={Landing}/> */}
              <Route exact path="/"><MainApp/></Route>
              {/* Auth Routes */}
              <AppRoute exact path="/signup" layout={AuthLayout} component={Signup}/>
              <AppRoute exact path="/login" layout={AuthLayout} component={Login}/>
              <AppRoute exact path="/reset-password" layout={AuthLayout} component={PasswordResetRequest}/>
              <AppRoute exact path="/reset-password/:token" layout={AuthLayout} component={PasswordResetChange}/>
            </ScrollToTop>
          </Switch>
        </Router>
      </Provider>
    )
  }
}

export default App;
